using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;

int t[10001], c[10001], p[10001], dp[1001];

signed main(void)
{
	int h1, m1, h2, m2; 
    scanf("%lld:%lld %lld:%lld", &h1, &m1, &h2, &m2);
	int t1 = h1 * 60 + m1, t2 = h2 * 60 + m2;
    int m = t2 - t1;
    int n;
	scanf("%lld", &n);
    for (int i = 1; i <= n; ++i)
    {
        scanf("%lld %lld %lld", &t[i], &c[i], &p[i]);
    }
    for (int i = 1; i <= n; ++i)
    {
        if (p[i] == 0)
        {
            for (int j = t[i]; j <= m; ++j)
            {
                dp[j] = max(dp[j], dp[j - t[i]] + c[i]);
            }
        }
        else
        {
            for (int num = 1; num <= p[i]; ++num)
            {
                for (int j = m; j >= num * t[i]; --j)
                {
                    dp[j] = max(dp[j], dp[j - t[i]] + c[i]);
                }
            }
        }
    }
    cout << dp[m];

	return false;
}
